const lines = FILE_CONTENT.split('\n');
const failures = [];
let inFailure = false;
let currentFailure = [];

for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  // Look for FAIL lines, error lines, assertion failures
  if (line.includes('FAIL') || line.includes('✗') || line.includes('error:') || line.includes('Error:') || line.includes('expect(') || line.includes('Expected') || line.includes('Received') || line.includes('AssertionError') || line.includes('TypeError') || line.includes('ReferenceError')) {
    // Get context around the failure
    const start = Math.max(0, i - 3);
    const end = Math.min(lines.length - 1, i + 10);
    const context = lines.slice(start, end + 1).join('\n');
    failures.push(context);
    i = end; // skip ahead
  }
}

// Also get the summary at the end
const last200 = lines.slice(-200).join('\n');
const summaryMatch = last200.match(/(\d+ pass|\d+ fail|Tests:.*|Test Suites:.*)/gi);

console.log("=== TEST FAILURES ===");
// Deduplicate and show unique failures
const seen = new Set();
for (const f of failures) {
  const key = f.substring(0, 100);
  if (!seen.has(key)) {
    seen.add(key);
    console.log(f);
    console.log('---');
  }
}

