// Find all log lines mentioning ws-ci-empty
const lines = FILE_CONTENT.split('\n');
const emptyWs = [];
for (const line of lines) {
  if (line.includes('ws-ci-empty')) {
    // Extract just the relevant JSON part
    const tsMatch = line.match(/\d{4}-\d{2}-\d{2}T[\d:.]+Z\s*(.*)/);
    const content = tsMatch ? tsMatch[1] : line;
    // Extract event field
    const eventMatch = content.match(/"event":"([^"]+)"/);
    const event = eventMatch ? eventMatch[1] : 'no-event';
    const reqMatch = content.match(/"requestId":"([^"]+)"/);
    const reqId = reqMatch ? reqMatch[1] : 'no-req';
    emptyWs.push(`[${event}] reqId=${reqId.substring(0,8)} ${content.substring(0, 200)}`);
  }
}

console.log(`Found ${emptyWs.length} log lines for ws-ci-empty:`);
emptyWs.forEach(l => console.log(l));

// Get the full proxy.context_injection.result line for ws-ci-empty
const lines = FILE_CONTENT.split('\n');
for (const line of lines) {
  if (line.includes('ws-ci-empty') && line.includes('context_injection.result')) {
    // Parse the JSON
    const jsonMatch = line.match(/\{.*\}/);
    if (jsonMatch) {
      try {
        const obj = JSON.parse(jsonMatch[0]);
        console.log("Context injection result for ws-ci-empty:");
        console.log(JSON.stringify(obj, null, 2));
      } catch {
        console.log("Raw line:", line.substring(line.indexOf('{')));
      }
    }
  }
}

