const lines = FILE_CONTENT.split('\n');
for (let i = 0; i < lines.length; i++) {
  const line = lines[i];
  if (line.includes('observer') || line.includes('anomal') || line.includes('contradict') || 
      line.includes('coherence') || line.includes('sessionEnd') || line.includes('session-end') ||
      line.includes('X-Brain-Session-End') || line.includes('session_end_handler') ||
      line.includes('onSessionEnd') || line.includes('handleSessionEnd')) {
    console.log(`${i+1}: ${line.trimEnd()}`);
  }
}

// Also look for any imports that could relate to observers
console.log("\n--- IMPORTS ---");
for (let i = 0; i < 30; i++) {
  console.log(`${i+1}: ${lines[i]?.trimEnd()}`);
}

