// edges to nonexistent records otherwise.
if (data.sessionId) {
  const sessionRecord = new RecordId("agent_session", data.sessionId);
  const [exists] = await surreal.query<[Array<{ id: RecordId }>]>(
    `SELECT id FROM $sess LIMIT 1;`,
    { sess: sessionRecord },
