// Create session invocation edge when session is resolved.
// NOTE: `$session` is a SurrealDB protected variable — use `$sess` instead.
// The sessionId may be either the agent_session PK (from X-Brain-Session header)
// or an external session ID (from Claude Code metadata.user_id). Look up by both
// PK and external_session_id, then RELATE only if found.
if (data.sessionId) {
  const sessionRecord = new RecordId("agent_session", data.sessionId);
  const [resolved] = await surreal.query<[Array<{ id: RecordId }>]>(
    `LET $by_pk = (SELECT id FROM $sess LIMIT 1);
     LET $by_ext = (SELECT id FROM agent_session WHERE external_session_id = $sid LIMIT 1);
     RETURN array::first($by_pk) ?? array::first($by_ext);`,
    { sess: sessionRecord, sid: data.sessionId },
  );
  if (resolved) {
    const resolvedRecord = resolved.id ?? (resolved as unknown as RecordId);
    await surreal.query(
      `RELATE $sess->invoked->$trace SET created_at = time::now();`,
      { sess: resolvedRecord, trace: traceRecord },
    );
  }
}

